mapper.select:
select * from tbl_dish_comment where 1=1

    and dish_id = #{params.dishId}


    and parent_id = #{params.parentId}


    and (content like concat('%',#{params.search},'%') or exists(select 1 from tbl_dish where tbl_dish.id = tbl_user_share.dish_id and tbl_dish.name like concat('%',#{params.search},'%')))

order by create_time desc
